from typing import List

def combination_sum(candidates: List[int], target: int) -> List[List[int]]:
    result = set()

    def backtrack(remaining, current):
        if remaining == 0:
            result.add(tuple(sorted(current)))
            return
        if remaining < 0:
            return
        for c in candidates:
            current.append(c)
            backtrack(remaining - c, current)
            current.pop()

    backtrack(target, [])
    return sorted([list(t) for t in result])
